import{_ as i,c as a,o as t,ah as e}from"./chunks/framework.DwHsq7Fg.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/curl.md","filePath":"basics_api/curl.md"}'),l={name:"basics_api/curl.md"};function h(p,s,n,k,d,r){return t(),a("div",null,s[0]||(s[0]=[e('<h3 id="⚙️-curl-універсальнии-інструмент-командного-рядка-для-роботи-з-url" tabindex="-1">⚙️ CURL: Універсальний інструмент командного рядка для роботи з URL <a class="header-anchor" href="#⚙️-curl-універсальнии-інструмент-командного-рядка-для-роботи-з-url" aria-label="Permalink to “⚙️ CURL: Універсальний інструмент командного рядка для роботи з URL”">​</a></h3><p><strong>Що це?</strong></p><p>CURL (Client URL) - це <strong>потужна утиліта командного рядка</strong>, яка використовується для передачі даних з або на сервер, використовуючи різноманітні протоколи, включаючи HTTP, HTTPS, FTP, SFTP, SMTP, POP3 та багато інших. Для розробників та тестувальників API CURL є незамінним інструментом завдяки своїй гнучкості та можливості безпосередньої взаємодії з веб-сервісами.</p><p><strong>Основні можливості та їх детальний огляд:</strong></p><ul><li><p><strong>📤 Надсилання HTTP-запитів:</strong></p><ul><li><strong>Вибір методу (<code>-X</code>):</strong> CURL дозволяє вказувати будь-який HTTP-метод: <code>GET</code>, <code>POST</code>, <code>PUT</code>, <code>DELETE</code>, <code>PATCH</code>, <code>HEAD</code>, <code>OPTIONS</code>. За замовчуванням використовується метод <code>GET</code>.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/resource](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Вказівка URL:</strong> Обов&#39;язковий параметр, що визначає адресу API-ендпоінта.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/data](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Додавання заголовків (<code>-H</code>):</strong> CURL дозволяє додавати будь-які HTTP-заголовки до запиту. Можна вказати кілька заголовків.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer YOUR_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/resource](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Передача даних у тілі запиту (<code>-d</code>):</strong> Використовується для методів, що передають дані (наприклад, <code>POST</code>, <code>PUT</code>, <code>PATCH</code>). Підтримує різні формати даних. <ul><li><strong>URL-encoded дані:</strong><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;param1=value1&amp;param2=value2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/resource](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>JSON дані:</strong><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;key&quot;: &quot;value&quot;}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/resource](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/resource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Передача файлів (<code>-F</code>):</strong> Для надсилання даних форми з файлами.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;file=@/path/to/your/file.txt&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/upload](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/upload</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li></ul></li></ul></li><li><p><strong>📥 Отримання відповідей API:</strong></p><ul><li><strong>Виведення в стандартний вивід (stdout):</strong> За замовчуванням CURL виводить тіло відповіді API в термінал.</li><li><strong>Збереження у файл (<code>-o</code> або <code>-O</code>):</strong><ul><li><code>-o</code>: Збереження відповіді у вказаний файл.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/data](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><code>-O</code>: Збереження відповіді у файл з ім&#39;ям, вказаним у URL.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/files/document.pdf](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/files/document.pdf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li></ul></li><li><strong>Відображення заголовків (<code>-i</code>):</strong> Включає заголовки HTTP-відповіді у вивід.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/data](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Відображення тільки заголовків (<code>-I</code>):</strong> Надсилає HEAD-запит та виводить лише заголовки відповіді.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/data](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Отримання інформації про запит/відповідь (<code>-v</code>):</strong> Режим verbose, що виводить детальну інформацію про процес передачі даних, включаючи запити, заголовки та відповіді.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/data](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li></ul></li><li><p><strong>🔑 Аутентифікація:</strong></p><ul><li><strong>Basic Auth (<code>-u</code>):</strong> Передача імені користувача та пароля.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> username:password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/protected](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/protected</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Bearer Token (<code>-H &quot;Authorization: Bearer YOUR_TOKEN&quot;</code>):</strong> Передача токена в заголовку.</li><li><strong>Інші методи:</strong> CURL підтримує й інші методи аутентифікації.</li></ul></li><li><p><strong>⚙️ Інші корисні опції:</strong></p><ul><li><strong>Слідування за перенаправленнями (<code>-L</code>):</strong> Якщо сервер повертає перенаправлення (наприклад, 301, 302), CURL автоматично перейде за новою адресою.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://example.com/old-url](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://example.com/old-url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Встановлення тайм-ауту (<code>-m</code>):</strong> Встановлення максимального часу очікування для запиту в секундах.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://api.example.com/slow-api](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://api.example.com/slow-api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li><strong>Ігнорування помилок SSL (<code>-k</code> або <code>--insecure</code>):</strong> Не рекомендується для продакшн-середовищ, але може бути корисним для тестування з самопідписаними сертифікатами.<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://insecure.example.com](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://insecure.example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li></ul></li></ul><p><strong>Візуалізація:</strong> Уявіть CURL як ваш <strong>термінальний інструмент суперсили</strong> 🦸‍♂️ для безпосередньої взаємодії з будь-яким URL. Ви можете відправляти складні запити, точно контролювати заголовки та дані, а також отримувати детальну інформацію про відповіді API прямо в командному рядку. Його гнучкість робить його незамінним для швидкого тестування та налагодження API.</p><p>CURL є потужним інструментом, який часто використовується в скриптах автоматизації, для швидкої перевірки API-ендпоінтів та для розуміння того, як API насправді працює на рівні HTTP-запитів та відповідей.</p>',7)]))}const c=i(l,[["render",h]]);export{g as __pageData,c as default};
